91:                             String globalContextName, Password dynamicJaasConfig) {
92:         if (dynamicJaasConfig != null) {
93:             JaasConfig jaasConfig = new JaasConfig(globalContextName, dynamicJaasConfig.value());
94:             AppConfigurationEntry[] contextModules = jaasConfig.getAppConfigurationEntry(globalContextName);
95:             if (contextModules == null || contextModules.length == 0)
96:                 throw new IllegalArgumentException("JAAS config property does not contain any login modules");
97:             else if (contextModules.length != 1)
98:                 throw new IllegalArgumentException("JAAS config property contains " + contextModules.length + " login modules, should be 1 module");
